/**
 * Flat key record returned to Swift. Mirrors the existing Swift
 * `TumpaKeyInfo` shape so the .appex's compose-UI / picker code
 * keeps working unchanged.
 */
public struct KeyInfo {
    /**
     * 40-char uppercase primary fingerprint.
     */
    public var fingerprint: String
    /**
     * Primary UID's full RFC 822 form
     * (e.g. `Alice <alice@example.com>`), or the fingerprint as a
     * fallback when the cert has no UID we can surface.
     */
    public var primaryUid: String
    /**
     * True iff secret key material is present in the keystore.
     * Card-backed keys have the public cert only and report `false`.
     */
    public var isSecret: Bool
    public var isRevoked: Bool
    public var isExpired: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * 40-char uppercase primary fingerprint.
         */fingerprint: String, 
        /**
         * Primary UID's full RFC 822 form
         * (e.g. `Alice <alice@example.com>`), or the fingerprint as a
         * fallback when the cert has no UID we can surface.
         */primaryUid: String, 
        /**
         * True iff secret key material is present in the keystore.
         * Card-backed keys have the public cert only and report `false`.
         */isSecret: Bool, isRevoked: Bool, isExpired: Bool) {
        self.fingerprint = fingerprint
        self.primaryUid = primaryUid
        self.isSecret = isSecret
        self.isRevoked = isRevoked
        self.isExpired = isExpired
    }
}

#if compiler(>=6)
extension KeyInfo: Sendable {}
#endif


extension KeyInfo: Equatable, Hashable {
    public static func ==(lhs: KeyInfo, rhs: KeyInfo) -> Bool {
        if lhs.fingerprint != rhs.fingerprint {
            return false
        }
        if lhs.primaryUid != rhs.primaryUid {
            return false
        }
        if lhs.isSecret != rhs.isSecret {
            return false
        }
        if lhs.isRevoked != rhs.isRevoked {
            return false
        }
        if lhs.isExpired != rhs.isExpired {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(fingerprint)
        hasher.combine(primaryUid)
        hasher.combine(isSecret)
        hasher.combine(isRevoked)
        hasher.combine(isExpired)
    }
}



