// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Inner-signature classification on a decrypt+verify outcome.
 *
 * Mirrors `libtumpa::decrypt::DecryptVerifyOutcome` but with `KeyInfo`
 * flattened to the fields the Mail extension's `MEMessageSigner`
 * actually needs.
 */

public enum DecryptVerifyOutcome {
    
    /**
     * Encrypt-only payload — no inner signature.
     */
    case unsigned
    /**
     * Inner signature present and verified.
     */
    case good(signer: KeyInfo, 
        /**
         * Full 40-char fingerprint of the key that actually signed
         * (may be a signing subkey, not the primary). This is the
         * VALIDSIG-shaped value the security popover should display.
         */verifierFingerprint: String
    )
    /**
     * Inner signature present, signer key in keystore, but the
     * signature did not verify.
     */
    case bad(signer: KeyInfo
    )
    /**
     * Inner signature present but the signer's public key isn't in
     * the keystore. `issuer_ids` carries 16-char key IDs and/or
     * 40-char fingerprints from the signature packet.
     */
    case unknownKey(issuerIds: [String]
    )
}


#if compiler(>=6)
extension DecryptVerifyOutcome: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeDecryptVerifyOutcome: FfiConverterRustBuffer {
    typealias SwiftType = DecryptVerifyOutcome

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> DecryptVerifyOutcome {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .unsigned
        
        case 2: return .good(signer: try FfiConverterTypeKeyInfo.read(from: &buf), verifierFingerprint: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .bad(signer: try FfiConverterTypeKeyInfo.read(from: &buf)
        )
        
        case 4: return .unknownKey(issuerIds: try FfiConverterSequenceString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: DecryptVerifyOutcome, into buf: inout [UInt8]) {
        switch value {
        
        
        case .unsigned:
            writeInt(&buf, Int32(1))
        
        
        case let .good(signer,verifierFingerprint):
            writeInt(&buf, Int32(2))
            FfiConverterTypeKeyInfo.write(signer, into: &buf)
            FfiConverterString.write(verifierFingerprint, into: &buf)
            
        
        case let .bad(signer):
            writeInt(&buf, Int32(3))
            FfiConverterTypeKeyInfo.write(signer, into: &buf)
            
        
        case let .unknownKey(issuerIds):
            writeInt(&buf, Int32(4))
            FfiConverterSequenceString.write(issuerIds, into: &buf)
            
        }
    }
}


