@_documentation(visibility: private)
#endif
public func FfiConverterTypeDecryptVerifyOutcome_lift(_ buf: RustBuffer) throws -> DecryptVerifyOutcome {
    return try FfiConverterTypeDecryptVerifyOutcome.lift(buf)
